// Process each lead item and enrich with scoring and personalization
const enrichedItems = [];

for (const item of $input.all()) {
  // Generate random score between 60-100
  const score = Math.floor(Math.random() * 41) + 60;

  // Extract data from the item
  const fullName = item.json.Full_name || 'there';
  const companyName = item.json.Company_name || 'your company';
  const jobTitle = item.json.Job_title || 'your role';
  const industry = item.json.Industry || 'your industry';

  // Create personalized message
  const personalizedMessage = `Hi ${fullName}, I noticed you're working as ${jobTitle} at ${companyName} in the ${industry} sector. I'd love to discuss how we can help accelerate your growth.`;

  // Get current timestamp
  const timestamp = new Date().toISOString();

  // Build enriched item
  enrichedItems.push({
    json: {
      full_name: fullName,
      job_title: jobTitle,
      company_name: companyName,
      industry: industry,
      score: score,
      personalized_message: personalizedMessage,
      timestamp: timestamp
    }
  });
}

return enrichedItems;

// This Code Node extracts only "email_type" from AI agent's output JSON text
// It safely parses nested JSON even if it's wrapped in markdown ```json blocks

return $input.all().map(item => {
  let rawOutput = item.json.output;
  let emailType = 'unknown'; // default fallback

  try {
    // Clean output by removing markdown code fences and extra text
    const cleaned = rawOutput
      .replace(/```json/g, '')
      .replace(/```/g, '')
      .trim();

    // Find the first valid JSON substring using regex
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      if (parsed.email_type) {
        emailType = parsed.email_type;
      }
    }
  } catch (error) {
    emailType = `error: ${error.message}`;
  }

  return {
    json: {
      email_type: emailType
    }
  };
});
